import { defineConfig } from '@hey-api/openapi-ts';

export default defineConfig({
  input: {
    path: 'https://cdn.jsdelivr.net/gh/cloudflare/api-schemas@main/openapi.json'
  },
  output: {
    importFileExtension: undefined,
    header: [
      '/* eslint-disable -- This file is auto-generated by @hey-api/openapi-ts */',
      '// biome-ignore-all format: This file is auto-generated by @hey-api/openapi-ts',
      '// biome-ignore-all lint: This file is auto-generated by @hey-api/openapi-ts'
    ],
    path: 'src/sdk'
    // tsConfigPath: undefined,
  },
  plugins: [
    {
      name: '@hey-api/sdk',
      validator: 'zod',
      operations: {
        strategy: 'byTags',
        containerName: (name) => `${name}Service`
      },
      includeInEntry: true,
      paramsStructure: 'flat'
    },
    {
      name: '@hey-api/client-ky',
      throwOnError: true,
      includeInEntry: true
    },
    {
      name: 'zod',
      metadata: true,
      includeInEntry: true
    },
    {
      name: '@hey-api/typescript',
      comments: true,
      enums: true,
      includeInEntry: true
    }
  ],
  parser: {
    hooks: {
      symbols: {
        getFilePath(symbol) {
          if (
            symbol.kind === 'class'
            // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition -- incorrect type narrowing
            && symbol.name?.endsWith('Service')
          ) {
            return `services/${symbol.name}`;
          }
        }
      }
    }
  }
});
